```plantuml
@startuml

title Modulo-matrícula/Informática

class Matrícula {
  -cliente: Client
  -tempo: Int
  -quadra: Turma
}

class Aluno {
  -id: Int
  -nome: String
  -locaçao: List<Matrícula>
}

class controleNúmeroMatrícula {
  -quantidade: Int
}

class Curso {
  -nome: String
  -quadra: List<Turma>
}

class Turma {
  -numero: Int
  -aluguel: Matrícula
  -ginasio: Curso
}

Aluno "1" *-- "0..*" Matrícula : composição <

Matrícula "1..*" *-- Turma : composição >

Curso "1..*" *-- "1" Turma : composição >

Turma ..|> controleNúmeroMatrícula

@enduml
```
